import React, { useEffect, useState, useCallback, useMemo } from 'react';
import api from '../api/axiosConfig';
import { useTheme } from '../context/ThemeContext';
import ReactMarkdown from 'react-markdown';
import { Trash2, Download, Archive, Calendar, ShieldCheck, Eye, X, BarChart3, AlignLeft } from 'lucide-react';
import toast from 'react-hot-toast';

const VaultPage = () => {
  const { isDark } = useTheme();
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedItem, setSelectedItem] = useState(null);

  /* ───────── API Actions ───────── */
  const fetchHistory = useCallback(async () => {
    try {
      const res = await api.get('/portfolio/history');
      setHistory(Array.isArray(res.data) ? res.data : []);
    } catch (err) {
      toast.error("VAULT_SYNC_FAILURE");
    } finally {
      setLoading(false);
    }
  }, []);

  const handleDelete = async (id) => {
    if (!window.confirm("PERMANENT_WIPE: Purge this node?")) return;
    try {
      await api.delete(`/portfolio/${id}`);
      setHistory(prev => prev.filter(item => item.id !== id));
      toast.success("DATA_PURGED");
    } catch (err) {
      toast.error("PURGE_ERROR");
    }
  };

  const handleDownload = async (item) => {
    try {
      const response = await api.post('/portfolio/export', item, { responseType: 'blob' });
      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `Strategy_${item.id}.pdf`);
      document.body.appendChild(link);
      link.click();
      link.remove();
    } catch (err) {
      toast.error("EXPORT_FAILED");
    }
  };

  useEffect(() => { fetchHistory(); }, [fetchHistory]);

  /* ───────── Global Theme Mapping ───────── */
  const theme = useMemo(() => ({
    bg: isDark ? '#000000' : '#ffffff',      // Pure Black background
    card: isDark ? '#0a0a0a' : '#fcfcfc',    // Slightly lighter black for cards
    text: isDark ? '#ffffff' : '#000000',    // High contrast text
    border: isDark ? '#1a1a1a' : '#e5e7eb',  // Subtle dark borders
    muted: isDark ? '#888' : '#666'
  }), [isDark]);

  if (loading) return <div style={{...centerStyle, color: 'var(--accent-primary)'}}>SYNCHRONIZING_VAULT...</div>;

  return (
    <div style={{...containerStyle, background: theme.bg, color: theme.text}}>
      {/* ── Page Header ── */}
      <div style={{...headerRow, borderBottom: `1px solid ${theme.border}`}}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
          <Archive size={28} color="var(--accent-primary)"/>
          <h2 style={{ fontSize: '1.6rem', fontWeight: 900, margin: 0, color: theme.text }}>STRATEGY_VAULT</h2>
        </div>
        <span style={{...vaultBadge, borderColor: 'var(--accent-primary)'}}>{history.length} NODES</span>
      </div>

      {/* ── List ── */}
      <div style={listStyle}>
        {history.length === 0 ? (
          <div style={{...emptyStyle, border: `1px dashed ${theme.border}`, color: theme.muted}}>NO_DATA_FOUND</div>
        ) : (
          history.map((item) => (
            <div key={item.id} className="vault-card" style={{...cardStyle, background: theme.card, border: `1px solid ${theme.border}`}}>
              <div style={{ flex: 1 }}>
                <div style={tagRow}>
                  <span style={{ fontSize: '0.8rem', color: theme.muted, display: 'flex', alignItems: 'center', gap: '6px' }}>
                    <Calendar size={14}/> {new Date(item.created_at).toLocaleDateString()}
                  </span>
                  <span style={{ fontSize: '0.8rem', color: 'var(--accent-primary)', fontWeight: 800, display: 'flex', alignItems: 'center', gap: '6px' }}>
                    <ShieldCheck size={14}/> RISK: {item.risk_score}
                  </span>
                </div>
                <h4 style={{ margin: '0 0 12px 0', color: theme.text, fontSize: '1.2rem', fontWeight: 700 }}>{item.goal}</h4>
              </div>

              <div style={{...actionColumn, borderLeft: `1px solid ${theme.border}`}}>
                <button onClick={() => setSelectedItem(item)} style={{...iconBtn, color: theme.muted}} title="View"><Eye size={22}/></button>
                <button onClick={() => handleDownload(item)} style={{...iconBtn, color: theme.muted}} title="Download"><Download size={22}/></button>
                <button onClick={() => handleDelete(item.id)} style={{...iconBtn, color: '#ef4444'}} title="Purge"><Trash2 size={22}/></button>
              </div>
            </div>
          ))
        )}
      </div>

      {/* ── Modal (OLED Black) ── */}
      {selectedItem && (
        <div style={modalOverlay(isDark)}>
          <div style={{...modalContent, background: theme.bg, border: `2px solid var(--accent-primary)`}}>
            <div style={{...modalHeader, background: isDark ? '#000000' : '#f5f5f5', borderBottom: `1px solid ${theme.border}`}}>
              <span style={{ color: 'var(--accent-primary)', fontWeight: 800 }}>NODE_DATA // SYNC_{selectedItem.id}</span>
              <button onClick={() => setSelectedItem(null)} style={{background:'none', border:'none', color: theme.text, cursor:'pointer'}}><X size={28}/></button>
            </div>
            <div style={modalBody}>
              <h3 style={{ color: theme.text, marginBottom: '2rem', fontSize: '1.8rem', fontWeight: 900 }}>{selectedItem.goal}</h3>
              <div className={isDark ? "md-dark" : "md-light"}>
                <p style={labelSmall}><AlignLeft size={16}/> SUMMARY</p>
                <ReactMarkdown>{selectedItem.summary}</ReactMarkdown>
                <hr style={{margin: '2rem 0', borderColor: theme.border}} />
                <p style={labelSmall}><AlignLeft size={16}/> RATIONALE</p>
                <ReactMarkdown>{selectedItem.rationale}</ReactMarkdown>
              </div>
            </div>
          </div>
        </div>
      )}

      <style>{`
        .md-dark p { color: #ffffff !important; line-height: 1.7; }
        .md-light p { color: #000000 !important; line-height: 1.7; }
        .vault-card:hover { border-color: var(--accent-primary) !important; }
        .reveal-node { animation: fadeIn 0.4s ease; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
      `}</style>
    </div>
  );
};

/* ── UI Constants ── */
const containerStyle = { padding: '4rem 2rem', maxWidth: '1000px', margin: '0 auto', minHeight: '100vh', transition: 'background 0.3s ease' };
const headerRow = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '3rem', paddingBottom: '1.5rem' };
const vaultBadge = { fontSize: '0.8rem', color: 'var(--accent-primary)', fontWeight: 900, padding: '6px 16px', borderRadius: '8px', border: '1px solid' };
const listStyle = { display: 'flex', flexDirection: 'column', gap: '1.5rem' };
const cardStyle = { display: 'flex', padding: '2rem', borderRadius: '20px', alignItems: 'center', transition: 'all 0.2s ease' };
const tagRow = { display: 'flex', gap: '20px', marginBottom: '10px' };
const actionColumn = { display: 'flex', gap: '20px', paddingLeft: '2rem', marginLeft: '1.5rem' };
const iconBtn = { background: 'none', border: 'none', cursor: 'pointer' };

